
.skill-tree-panel {
  display: flex;
  flex-direction: column;
  min-height: 0;
  height: 100%;
  padding: 12px 14px;
  color: #e8efe3;
  overflow-y: auto;
}

.panel-title {
  margin: 0 0 10px;
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.12em;
}

.skill-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.skill-item {
  padding: 10px 12px;
  border: 1px solid rgb(255 255 255 / 10%);
  border-radius: 8px;
  background: rgb(255 255 255 / 3%);
}

.skill-item--active {
  border-color: rgb(240 217 140 / 35%);
  background: rgb(240 217 140 / 6%);
}

.skill-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 6px;
}

.skill-name {
  font-size: 14px;
  font-weight: 700;
}

.skill-badge {
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 10px;
  letter-spacing: 0.06em;
}

.skill-badge--on {
  background: rgb(240 217 140 / 18%);
  color: #f0d98c;
}

.skill-badge--off {
  background: rgb(255 255 255 / 8%);
  color: rgb(232 239 227 / 58%);
}

.skill-effect,
.skill-note,
.skill-story {
  margin: 0;
  font-size: 12px;
  line-height: 1.45;
}

.skill-effect {
  margin-bottom: 4px;
  color: #dce8d0;
}

.skill-note {
  margin-bottom: 8px;
  color: rgb(232 239 227 / 58%);
}

.skill-story {
  color: rgb(232 239 227 / 72%);
}

.skill-button {
  width: 100%;
  padding: 8px 10px;
  border: 1px solid rgb(240 217 140 / 35%);
  border-radius: 6px;
  background: rgb(240 217 140 / 10%);
  color: #f0d98c;
  font: inherit;
  font-size: 12px;
  cursor: pointer;
  transition:
    background 0.15s ease,
    transform 0.15s ease;
}

.skill-button:hover:not(:disabled) {
  background: rgb(240 217 140 / 18%);
}

.skill-button:active:not(:disabled) {
  transform: translateY(1px);
}

.skill-button:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}
