
.game-shell {
  width: 100%;
  aspect-ratio: 16 / 9;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border: 1px solid rgb(255 255 255 / 10%);
  border-radius: 10px;
  background: #0d1410;
}

.tab-content {
  flex: 1;
  min-height: 0;
  position: relative;
}

.tab-pane {
  position: absolute;
  inset: 0;
  min-height: 0;
}
