
.resource-hud {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 10px 16px;
  padding: 10px 14px;
  border-bottom: 1px solid rgb(255 255 255 / 12%);
  background: linear-gradient(180deg, rgb(18 28 22 / 92%), rgb(12 18 15 / 88%));
  color: #e8efe3;
}

.resource-item {
  display: flex;
  align-items: baseline;
  gap: 8px;
  min-width: 0;
}

.resource-item--highlight .resource-value {
  color: #f0d98c;
}

.resource-label {
  font-size: 12px;
  letter-spacing: 0.08em;
  color: rgb(232 239 227 / 72%);
}

.resource-value {
  font-size: 22px;
  font-weight: 700;
  line-height: 1;
  font-variant-numeric: tabular-nums;
}

.resource-hint {
  flex: 1 1 100%;
  margin: 0;
  font-size: 11px;
  line-height: 1.4;
  color: rgb(232 239 227 / 58%);
}
