
.achievement-panel {
  display: flex;
  flex-direction: column;
  min-height: 0;
  height: 100%;
  padding: 12px 14px;
  color: #e8efe3;
  overflow-y: auto;
}

.panel-title {
  margin: 0 0 10px;
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.12em;
}

.achievement-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin: 0;
  padding: 0;
  list-style: none;
}

.achievement-item {
  padding: 10px 12px;
  border: 1px solid rgb(255 255 255 / 10%);
  border-radius: 8px;
  background: rgb(255 255 255 / 3%);
}

.achievement-item--unlocked {
  border-color: rgb(184 208 200 / 35%);
  background: rgb(184 208 200 / 8%);
}

.achievement-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 6px;
}

.achievement-name {
  font-size: 14px;
  font-weight: 700;
}

.achievement-badge {
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 10px;
  letter-spacing: 0.06em;
}

.achievement-badge--on {
  background: rgb(184 208 200 / 18%);
  color: #b8d0c8;
}

.achievement-badge--off {
  background: rgb(255 255 255 / 8%);
  color: rgb(232 239 227 / 58%);
}

.achievement-desc {
  margin: 0;
  font-size: 12px;
  line-height: 1.45;
  color: rgb(232 239 227 / 72%);
}

.system-log {
  margin-top: 16px;
  padding-top: 14px;
  border-top: 1px dashed rgb(255 255 255 / 12%);
}

.log-title {
  margin: 0 0 8px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.08em;
  color: rgb(232 239 227 / 72%);
}

.log-list {
  margin: 0;
  padding: 0;
  list-style: none;
}

.log-list li {
  padding: 4px 0;
  font-size: 11px;
  line-height: 1.4;
  color: rgb(232 239 227 / 58%);
}
