
.tab-nav {
  display: flex;
  gap: 6px;
  padding: 8px 12px;
  border-bottom: 1px solid rgb(255 255 255 / 10%);
  background: rgb(8 12 10 / 92%);
}

.tab-button {
  flex: 1;
  padding: 8px 10px;
  border: 1px solid rgb(255 255 255 / 10%);
  border-radius: 6px;
  background: rgb(255 255 255 / 4%);
  color: rgb(232 239 227 / 72%);
  font: inherit;
  font-size: 12px;
  letter-spacing: 0.08em;
  cursor: pointer;
  transition:
    background 0.15s ease,
    border-color 0.15s ease,
    color 0.15s ease;
}

.tab-button:hover {
  background: rgb(255 255 255 / 8%);
}

.tab-button--active {
  border-color: rgb(240 217 140 / 35%);
  background: rgb(240 217 140 / 10%);
  color: #f0d98c;
}
